 70→// Enqueue styles and scripts
 71→function hone_landing_enqueue_assets() {
 72→    global $class_names;
 73→
 74→    $theme_version = wp_get_theme()->get('Version');
 75→    $theme_uri = get_template_directory_uri();
 76→
 77→    // Always load main.min.css - contains all common styles (reset, settings, parts)
 78→    wp_enqueue_style(
 79→        'hone-main-style',
 80→        $theme_uri . '/static/css/main.min.css',
 81→        array(),
 82→        $theme_version
 83→    );
 84→
 85→    // Early return if no class_names set
 86→    if (empty($class_names) || !is_array($class_names)) {
 87→        return;
 88→    }
 89→
 90→    // Check if this template has page-specific styles
 91→    $matches = array_intersect($class_names, HONE_PAGE_TEMPLATES);
 92→
 93→    // Load all matching page-specific styles in order
 94→    // This allows for layered styles (e.g., base 'mens-hrt-aol' + specific 'mens-hrt-aol-forbes')
 95→    if (!empty($matches)) {
 96→        $dependencies = array('hone-main-style'); // First match depends on main styles
 97→        
 98→        foreach ($matches as $matched_class) {
 99→            $css_file = get_template_directory() . '/static/css/pages/' . $matched_class . '.css';
100→            if (file_exists($css_file)) {
101→                wp_enqueue_style(
102→                    'hone-page-' . $matched_class,
103→                    $theme_uri . '/static/css/pages/' . $matched_class . '.css',
104→                    $dependencies,
105→                    $theme_version,
106→                    'all'
107→                );
108→                // Make next stylesheet depend on this one to maintain load order
109→                $dependencies = array('hone-page-' . $matched_class);
110→            }
111→        }
112→    }
113→    
114→    // Enqueue main JavaScript (always loaded - contains trackQuizEvent)
115→    wp_enqueue_script(
116→        'hone-main-script',
117→        $theme_uri . '/static/js/dist/combined.js',
118→        array(),
119→        $theme_version,
120→        true
121→    );
122→}
123→add_action('wp_enqueue_scripts', 'hone_landing_enqueue_assets');
124→
125→/**
126→ * Register page-specific JavaScript bundles
127→ * 
128→ * These bundles are built with esbuild and include all dependencies
129→ * (except jQuery which is loaded via WordPress).
130→ * 
131→ * Each bundle includes: Slick carousel + relevant utilities
132→ * 
133→ * Usage in templates:
134→ *   wp_enqueue_script('hone-page-article-trt-new-copy');
135→ */
136→function hone_register_bundles() {
137→    $theme_version = wp_get_theme()->get('Version');
138→    $theme_uri = get_template_directory_uri();
139→    $theme_dir = get_template_directory();
140→    
141→    // Register jQuery Migrate (dependency for Slick)
142→    wp_register_script(
143→        'jquery-migrate',
144→        $theme_uri . '/static/js/dist/jquery-migrate-1.2.1.min.js',
145→        array('jquery'),
146→        '1.2.1',
147→        true
148→    );
149→    
150→    // Register Slick carousel
151→    wp_register_script(
152→        'slick-carousel',
153→        $theme_uri . '/static/js/dist/slick.min.js',
154→        array('jquery', 'jquery-migrate'),
155→        '1.8.1',
156→        true
157→    );
158→    
159→    // Register each page bundle with jQuery, jQuery Migrate, and Slick as dependencies
160→    foreach (HONE_PAGE_TEMPLATES as $page) {
161→        $bundle_path = $theme_dir . '/static/js/dist/pages/' . $page . '.bundle.min.js';
162→        $bundle_url = $theme_uri . '/static/js/dist/pages/' . $page . '.bundle.min.js';
163→        if (file_exists($bundle_path)) {
164→            wp_register_script(
165→                'hone-page-' . $page,
166→                $bundle_url,
167→                array('jquery', 'jquery-migrate', 'slick-carousel'),
168→                $theme_version,
169→                true
170→            );
171→        }
172→    }
173→}
174→add_action('wp_enqueue_scripts', 'hone_register_bundles', 5);
