/**
 * Mens OPT Enhanced PDP
 * Page-specific styles for page-mens-opt-enhanced-pdp.php
 *
 * Desktop-first: base styles target desktop (1440px).
 * Tablet/mobile overrides via $medium-screen-and-smaller (max-width: 1024px).
 * Mobile-only refinements via $small-screen-only (max-width: 600px).
 */
@use '../variables/colors' as colors;
@use '../variables/fonts' as fonts;
@use '../variables/layout' as layout;

.mens-opt-enhanced-pdp {

	> *:not(.linkbar, .navbar, .site-footer) > .container {
		max-width: 1440px;
		margin: 0 auto;
	}
	.extended-center-border-above,
	.extended-center-border-below {
		@media #{layout.$medium-screen-and-smaller} {
			&::before,
			&::after {
				display: none !important;
			}
		}
	}

	/*
	* =============================
	* Hero
	* =============================
	*/
	.boost-your-testosterone.hero {
		background-color: colors.$color-white;
		padding: fonts.rem(40px) fonts.rem(64px);
		@media #{layout.$medium-screen-and-smaller} {
			padding: fonts.rem(16px) fonts.rem(32px) fonts.rem(40px);
			flex-direction: column;
			gap: fonts.rem(24px);
		}
		@media #{layout.$small-screen-only} {
			padding-inline: fonts.rem(16px);
		}

		.container.grid {
			gap: fonts.rem(64px);
			grid-template-columns: 600px 1fr;
			@media #{layout.$medium-screen-and-smaller} {
				grid-template-columns: 1fr;
				gap: fonts.rem(24px);
			}
		}

		.container {
			@media #{layout.$medium-screen-and-smaller} {
				display: flex;
				flex-direction: column;
				gap: fonts.rem(24px);
