				padding: 0;
				gap: fonts.rem(40px);
				padding: 0;
				background-color: transparent;
			}
		}

		// Title
		.title-block {
			text-align: center;

			.title {
				font-family: fonts.$STIX-Two-Text;
				font-weight: 400;
				font-size: fonts.rem(54px);
				line-height: 1;
				letter-spacing: -1.08px;
				color: colors.$color-black;
				@media #{layout.$medium-screen-and-smaller} {
					font-size: fonts.rem(36px);
					letter-spacing: -0.72px;
				}
			}
		}

		// Cards row
		.timeline-wrapper {
			padding: 0;
		}

		.benefits-timeline-carousel {
			display: flex;
			justify-content: center;
			align-items: stretch; // all cards same height so dividers align
			width: 100%;
			@media #{layout.$medium-screen-and-smaller} {
				justify-content: flex-start;
				overflow-x: auto;
				-webkit-overflow-scrolling: touch;
				scrollbar-width: none;

				&::-webkit-scrollbar {
					display: none;
				}
			}
		}

		// Individual card
		// Image has fixed height so the divider line stays at a constant
		// vertical position across all cards during expand/collapse.
		.timeline-card {
			display: flex;
			flex-direction: column;
			gap: fonts.rem(8px);
			width: 250px;
			flex-shrink: 0;
			opacity: 0.8;
			cursor: pointer;
			transition: width 0.4s ease, opacity 0.4s ease;
			@media #{layout.$medium-screen-and-smaller} {
				max-width: 325px;
				width: 100vw;
				opacity: 1;
				cursor: default;
				transition: none;
			}
			&:first-child {
				margin-left: fonts.rem(32px);
				@media #{layout.$small-screen-only} {
					margin-left: fonts.rem(16px);
				}
				@media only screen and (max-width: 315px) {
					margin-left: fonts.rem(8px);
				}
			}
			&:last-child {
				margin-right: fonts.rem(32px);
				@media #{layout.$small-screen-only} {
					margin-right: fonts.rem(16px);
				}
				@media only screen and (max-width: 315px) {
					margin-right: fonts.rem(8px);
				}
			}

			// Image — fixed height, image sits at the bottom
			.image-wrapper {
				padding: 0 fonts.rem(8px);
				height: 296px;
				display: flex;
				align-items: flex-end;
				@media #{layout.$medium-screen-and-smaller} {
					height: auto;
					align-items: stretch;
				}

				img {
					width: 100%;
					aspect-ratio: 1 / 1;
					object-fit: cover;
					border-radius: 15px;
					display: block;
					transition: border-radius 0.4s ease;
					@media #{layout.$medium-screen-and-smaller} {
						border-radius: 20px;
					}
				}
			}

			// Divider: dot + line — the anchored midline
			.divider-wrapper {
				display: flex;
				align-items: center;
				gap: fonts.rem(8px);
				padding-bottom: fonts.rem(8px);
				padding-left: fonts.rem(8px);

				.dot {
					width: 12px;
					height: 12px;
					border-radius: 8px;
					border: 3px solid #20C475;
					background: colors.$color-white;
					flex-shrink: 0;
					box-sizing: border-box;
					// @media #{layout.$medium-screen-and-smaller} {
					// 	border-color: colors.$color-gray;
					// 	background: #D9D9D9;
					// }
				}

				.line {
					flex: 1;
					height: 1px;
					background-color: colors.$color-gray;
				}
			}

			// Content: day, heading, body
			.content-wrapper {
				display: flex;
				flex-direction: column;
				gap: fonts.rem(8px);
				padding: 0 fonts.rem(8px);

				.day {
					font-family: fonts.$DM-Sans;
					font-weight: 400;
					font-size: fonts.rem(14px);
					line-height: 1.1;
					letter-spacing: -0.28px;
					color: colors.$color-black;
				}

				.heading {
					font-family: fonts.$DM-Sans;
					font-weight: 500;
					font-size: fonts.rem(18px);
					line-height: 1.1;
					letter-spacing: -0.36px;
					color: colors.$color-black;
					max-height: 0;
					overflow: hidden;
					opacity: 0;
					transition: max-height 0.4s ease, opacity 0.3s ease;
					@media #{layout.$medium-screen-and-smaller} {
						max-height: none;
						overflow: visible;
						opacity: 1;
					}
				}

				.body {
					font-family: fonts.$DM-Sans;
					font-weight: 400;
					font-size: fonts.rem(14px);
					line-height: 1.4;
					letter-spacing: -0.14px;
					color: colors.$color-black;
					max-height: 0;
					overflow: hidden;
					opacity: 0;
					transition: max-height 0.4s ease, opacity 0.3s ease;
					@media #{layout.$medium-screen-and-smaller} {
						max-height: none;
						overflow: visible;
						opacity: 1;
					}
				}
			}

			// Active state
			&.active {
				width: 312px;
				opacity: 1;
				@media #{layout.$medium-screen-and-smaller} {
					max-width: 325px;
					width: 100vw;
				}

				.image-wrapper img {
					border-radius: 22.5px;
					@media #{layout.$medium-screen-and-smaller} {
						border-radius: 20px;
					}
				}

				.content-wrapper {
					.heading {
						max-height: 100px;
						opacity: 1;
					}

					.body {
						max-height: 300px;
						opacity: 1;
					}
				}
			}
		}
	}

