125→/**
126→ * Register page-specific JavaScript bundles
127→ * 
128→ * These bundles are built with esbuild and include all dependencies
129→ * (except jQuery which is loaded via WordPress).
130→ * 
131→ * Each bundle includes: Slick carousel + relevant utilities
132→ * 
133→ * Usage in templates:
134→ *   wp_enqueue_script('hone-page-article-trt-new-copy');
135→ */
136→function hone_register_bundles() {
137→    $theme_version = wp_get_theme()->get('Version');
138→    $theme_uri = get_template_directory_uri();
139→    $theme_dir = get_template_directory();
140→    
141→    // Register jQuery Migrate (dependency for Slick)
142→    wp_register_script(
143→        'jquery-migrate',
144→        $theme_uri . '/static/js/dist/jquery-migrate-1.2.1.min.js',
145→        array('jquery'),
146→        '1.2.1',
147→        true
148→    );
149→    
150→    // Register Slick carousel
151→    wp_register_script(
152→        'slick-carousel',
153→        $theme_uri . '/static/js/dist/slick.min.js',
154→        array('jquery', 'jquery-migrate'),
155→        '1.8.1',
156→        true
157→    );
158→    
159→    // Register each page bundle with jQuery, jQuery Migrate, and Slick as dependencies
160→    foreach (HONE_PAGE_TEMPLATES as $page) {
161→        $bundle_path = $theme_dir . '/static/js/dist/pages/' . $page . '.bundle.min.js';
162→        $bundle_url = $theme_uri . '/static/js/dist/pages/' . $page . '.bundle.min.js';
163→        if (file_exists($bundle_path)) {
164→            wp_register_script(
165→                'hone-page-' . $page,
166→                $bundle_url,
167→                array('jquery', 'jquery-migrate', 'slick-carousel'),
168→                $theme_version,
169→                true
170→            );
171→        }
172→    }
173→}
