117→function initQuiz() {
118→	const questionElement = document.getElementById("question");
119→	const optionsElement = document.getElementById("options");
120→	const ctaButton = document.getElementById("quiz-cta");
121→	const questionContainer = document.getElementsByClassName("question-container")[0];
122→	const resultsContainer = document.getElementsByClassName("results-container")[0];
123→	const progress = document.getElementsByClassName("progress")[0];
124→	
125→	if (!questionElement || !optionsElement || !questionContainer || !resultsContainer || !progress) {
126→		return;
127→	}
128→	
129→	let currentQuestion = 0;
130→
131→	function showQuestion() {
132→		const question = quizData[currentQuestion];
133→		questionContainer.classList.remove('question' + '-' + (question.id - 1));
134→		questionContainer.classList.add('question' + '-' + question.id);
135→		questionElement.innerHTML = question.title;
136→		optionsElement.innerHTML = "";
137→		
138→		question.options.forEach(option => {
139→			const button = document.createElement("button");
140→			button.innerText = option.value;
141→			button.classList.add('option-button', question.type);
142→			button.setAttribute('data-answer', option.id);
143→			
144→			if (question.type === 'multi-select') {
145→				ctaButton.style.display = 'block';
146→				ctaButton.classList.add('disabled');
147→				ctaButton.addEventListener("click", selectAnswer);
148→				const checkbox = document.createElement("span");
149→				checkbox.classList.add('checkbox');
150→				button.insertBefore(checkbox, button.firstChild);
151→				button.addEventListener("click", selectMulti);
152→			} else {
153→				ctaButton.style.display = 'none';
154→				button.addEventListener("click", selectAnswer);
155→			}
156→			optionsElement.appendChild(button);
157→		});
158→	}
159→
160→	function selectMulti() {
161→		if (this.classList.contains('selected')) {
162→			this.classList.remove('selected');
163→		} else {
164→			this.classList.add('selected');
165→		}
166→
167→		// Behavior if 'none' or 'no problems' selected
168→		const noneOption = quizData[currentQuestion].options.length - 1;
169→		let selectedElements = document.getElementsByClassName("selected");
170→		
171→		if (this.dataset.answer == noneOption) {
172→			Array.from(selectedElements).forEach(element => {
173→				if (element.dataset.answer != noneOption) {
174→					element.classList.remove('selected');
175→				}
176→			});
177→		} else {
178→			Array.from(selectedElements).forEach(element => {
179→				if (element.dataset.answer == noneOption) {
180→					element.classList.remove('selected');
181→				}
182→			});
183→		}
184→
185→		if (selectedElements.length > 0) {
186→			ctaButton.classList.remove('disabled');
187→		} else {
188→			ctaButton.classList.add('disabled');
189→		}
190→	}
