192→	function bindClickEvents() {
193→		let ctaButtons = document.getElementsByClassName('quiz-end-cta');
194→		if (ctaButtons) {
195→			Array.from(ctaButtons).forEach((button) => {
196→				button.addEventListener("click", (e) => {
197→					if (typeof trackQuizEvent === 'function') {
198→						trackQuizEvent('last_question', e.target.innerText);
199→					}
200→				});
201→			});
202→		}
203→	}
204→
205→	function selectAnswer(e) {
206→		if (e.target.id === 'quiz-cta') {
207→			const selectedElements = document.getElementsByClassName("selected");
208→			let options = '';
209→			if (selectedElements) {
210→				Array.from(selectedElements).forEach((element, index) => {
