265→/**
266→ * =============================
267→ * PARALLAX MARQUEE EFFECT
268→ * =============================
269→ */
270→
271→function initMarqueeParallax() {
272→	const monitorSection = document.querySelector('.monitor-for-early-indicators');
273→	const diseaseRows = document.querySelectorAll('.monitor-for-early-indicators .disease-row-list');
274→	
275→	if (!monitorSection || diseaseRows.length === 0) {
276→		return;
277→	}
278→
279→	let ticking = false;
280→	
281→	function updateMarqueeParallax() {
282→		const rect = monitorSection.getBoundingClientRect();
283→		const viewportHeight = window.innerHeight;
284→		const sectionHeight = rect.height;
285→		
286→		if (rect.top <= viewportHeight && rect.bottom >= 0) {
287→			const startPoint = viewportHeight;
288→			const endPoint = -sectionHeight;
289→			const currentPosition = rect.top;
290→			
291→			const totalDistance = startPoint - endPoint;
292→			const currentDistance = startPoint - currentPosition;
293→			const progress = Math.max(0, Math.min(1, currentDistance / totalDistance));
294→			
295→			diseaseRows.forEach((row, index) => {
296→				const scrollWidth = row.scrollWidth / 2;
297→				const maxOffset = scrollWidth;
298→				
299→				let speed, direction;
300→				switch (index) {
301→					case 0:
302→						speed = 0.125;
303→						direction = 1;
304→						break;
305→					case 1:
306→						speed = 0.15;
307→						direction = -1;
308→						break;
309→					case 2:
310→						speed = 0.1;
311→						direction = 1;
312→						break;
313→					default:
314→						speed = 0.1;
315→						direction = 1;
316→				}
317→				
318→				const baseOffset = progress * maxOffset * speed * direction;
319→				const offset = ((baseOffset % maxOffset) + maxOffset) % maxOffset;
320→				
321→				if (direction === 1) {
322→					row.style.transform = `translateX(-${offset}px)`;
323→				} else {
324→					row.style.transform = `translateX(${offset - maxOffset}px)`;
325→				}
326→			});
327→		}
328→		
329→		ticking = false;
330→	}
331→	
332→	function requestTick() {
333→		if (!ticking) {
334→			requestAnimationFrame(updateMarqueeParallax);
335→			ticking = true;
336→		}
337→	}
338→	
339→	window.addEventListener('scroll', requestTick, { passive: true });
340→	window.addEventListener('resize', requestTick, { passive: true });
341→	
342→	updateMarqueeParallax();
343→}
