384→			slidesToShow: 4,
385→			infinite: false,
386→			slidesToScroll: 1,
387→			dots: true,
388→			arrows: true,
389→			draggable: false,
390→			responsive: [
391→				{
392→					breakpoint: 768,
393→					settings: {
394→						slidesToShow: 1,
395→						slidesToScroll: 1,
396→						infinite: true,
397→					}
398→				},
399→				{
400→					breakpoint: 1280,
401→					settings: {
402→						slidesToShow: 2,
403→						slidesToScroll: 1
404→					}
405→				}
406→			]
407→		});
408→
409→		// Infographic carousel
410→		const infographicParams = {
411→			centerMode: true,
412→			centerPadding: '0px',
413→			adaptiveHeight: true,
414→		};
415→		initCarousel(infographicParams, '.infographic', true);	
416→
417→		/**
418→		 * =============================
419→		 * INFOGRAPHIC BUTTONS FUNCTIONALITY
420→		 * =============================
421→		 */
422→		// Update active button state when slide changes (in addition to default dot behavior)
423→		$('.infographic-carousel').on('beforeChange', function(event, slick, currentSlide, nextSlide) {
424→			// Update active button state
425→			$('.infographic-button').removeClass('active');
426→			$('.infographic-button').eq(nextSlide).addClass('active');
427→		});
428→
429→		// Infographic button click handlers - navigate to specific slide
430→		$('.infographic-button').on('click', function() {
431→			// Create a mapping of data-target to slide index
432→			var targetKey = $(this).data('target');
433→			var slideIndex = -1;
434→			
435→			// Find the correct index by iterating through slides
436→			$('.infographic-content').each(function(index) {
437→				if ($(this).data('id') === targetKey) {
438→					slideIndex = index;
439→					return false; // break the loop
440→				}
441→			});
442→			
443→			if (slideIndex >= 0) {
444→				$('.infographic-carousel').slick('slickGoTo', slideIndex);
445→			}
446→		});
447→
448→		// Set initial active state on first button
449→		$('.infographic-button').first().addClass('active');
450→	});
451→}
