454→/**
455→ * =============================
456→ * ACCORDION FUNCTIONALITY
457→ * =============================
458→ */
459→
460→function initAccordion() {
461→	const acc = document.getElementsByClassName("accordion-slide");
462→
463→	if (!acc || acc.length === 0) {
464→		return;
465→	}
466→
467→	const toggleAccordion = (e) => {
468→		let target = e.currentTarget;
469→		if (!target.classList.contains("active")) {
470→			Array.from(acc).forEach((slide) => {
471→				slide.classList.remove("active");
472→				slide.children[1].style.display = "none";
473→			});
474→			target.classList.add("active");
475→			target.children[1].style.display = "block";
476→		} else {
477→			target.classList.remove("active");
478→			target.children[1].style.display = "none";
479→		}
480→	};
481→
482→	Array.from(acc).forEach((slide) => {
483→		slide.addEventListener("click", (e) => toggleAccordion(e));
484→	});
485→}
486→
487→/**
488→ * =============================
489→ * REVIEWS EXPAND/COLLAPSE
490→ * =============================
491→ */
492→
493→function initReviewsExpand() {
494→	const buttons = document.querySelectorAll('.quote-attribution');
495→	
496→	buttons.forEach(button => {
497→		button.addEventListener('click', function() {
498→			let dots = this.parentNode.querySelector('#dots');
499→			let moreText = this.parentNode.querySelector('#more');
500→			
501→			if (dots && moreText) {
502→				if (dots.style.display === "none") {
503→					dots.style.display = "inline";
504→					this.innerHTML = "Read more";
505→					moreText.style.display = "none";
506→				} else {
507→					dots.style.display = "none";
