/**
 * Womens Hormone Imbalance Hero Variant
 * Page-specific styles for the enhanced PDP hero section only.
 * All other section styles are loaded via the base womens-hormone-imbalance.css.
 *
 * Desktop-first: base styles target desktop (1440px).
 * Tablet/mobile overrides via $medium-screen-and-smaller (max-width: 1024px).
 * Mobile-only refinements via $small-screen-only (max-width: 600px).
 */
@use '../variables/colors' as colors;
@use '../variables/fonts' as fonts;
@use '../variables/layout' as layout;

.womens-hormone-imbalance-hero {

	/*
	* =============================
	* Hero
	* =============================
	*/
	.hone-your-hormones.hero {
		background-color: colors.$color-white;
		padding: fonts.rem(40px) fonts.rem(64px);
		@media #{layout.$medium-screen-and-smaller} {
			padding: fonts.rem(16px) fonts.rem(32px) fonts.rem(40px);
			flex-direction: column;
			gap: fonts.rem(24px);
		}
		@media #{layout.$small-screen-only} {
			padding-inline: fonts.rem(16px);
		}

		.container.grid {
			max-width: 1440px;
			margin: 0 auto;
			gap: fonts.rem(64px);
			grid-template-columns: 600px 1fr;
			@media #{layout.$medium-screen-and-smaller} {
				grid-template-columns: 1fr;
				gap: fonts.rem(24px);
			}
		}

		.container {
			@media #{layout.$medium-screen-and-smaller} {
				display: flex;
				flex-direction: column;
				gap: fonts.rem(24px);
			}
		}

		// Left column — video/gif
		.media-wrapper {
			padding: 0;
			display: flex;
			align-items: center;
			background-color: colors.$color-white;
			@media #{layout.$medium-screen-and-smaller} {
				order: 1;
			}

			.media-block {
				width: 600px;
				aspect-ratio: 1 / 1;
				@media #{layout.$medium-screen-and-smaller} {
					width: 100%;
					max-width: fonts.rem(600px);
					height: auto;
					margin-left: auto;
					margin-right: auto;
				}

				video {
					width: 100%;
					height: 100%;
					object-fit: cover;
				}
			}
		}

		// Right column — content
		.content-wrapper {
			padding: 0;
			display: flex;
			flex-direction: column;
			justify-content: center;
			gap: fonts.rem(40px);
			@media #{layout.$medium-screen-and-smaller} {
				order: 2;
				gap: fonts.rem(24px);
			}

			// Title
			.title-block h2 {
				font-family: fonts.$STIX-Two-Text;
				font-weight: 400;
				font-size: fonts.rem(54px);
				line-height: 1;
				letter-spacing: -1.08px;
				color: colors.$color-black;
				max-width: 576px;
				@media #{layout.$medium-screen-and-smaller} {
					font-size: fonts.rem(36px);
					letter-spacing: -0.72px;
					max-width: none;
				}
			}

			// Description with left border
			.content-block {
				p {
					border-left: 2px solid rgba(96, 91, 82, 0.2);
					padding-left: fonts.rem(12px);
					font-family: fonts.$DM-Sans;
					font-weight: 500;
					font-size: fonts.rem(22px);
					line-height: 1.1;
					letter-spacing: -0.44px;
					color: colors.$color-black;
					@media #{layout.$medium-screen-and-smaller} {
						font-size: fonts.rem(18px);
						letter-spacing: -0.36px;
						padding-left: fonts.rem(8px);
					}
				}
			}

			// CTA block
			.cta-block {
				display: flex;
				flex-direction: column;
				gap: fonts.rem(8px);
				width: 100%;

				.cta-wrapper {
					width: 100%;
				}

				a {
					width: 100%;
					height: 48px;
					border-radius: 2px;
					padding: 0 fonts.rem(48px);
					box-sizing: border-box;
				}
			}

			// Badges
			.badges-wrapper {
				margin-top: fonts.rem(-32px);
				display: flex;
				flex-wrap: wrap;
				align-items: center;
				justify-content: center;
				gap: fonts.rem(10px);
				@media #{layout.$medium-screen-and-smaller} {
					margin-top: fonts.rem(-16px);
				}

				.badge {
					display: flex;
					align-items: center;
					height: 20px;

					img {
						width: auto;
						height: 24px;
					}

					span {
						font-family: fonts.$DM-Sans;
						font-weight: 400;
						font-size: fonts.rem(14px);
						line-height: 1.4;
						letter-spacing: -0.28px;
						color: colors.$color-gray;
						text-align: center;
					}
				}
			}
		}
	}
}

