				}
			}

			// Badges
			.badges-wrapper {
				margin-top: fonts.rem(-32px);
				display: flex;
				flex-wrap: wrap;
				align-items: center;
				justify-content: center;
				gap: fonts.rem(10px);
				@media #{layout.$medium-screen-and-smaller} {
					margin-top: fonts.rem(-16px);
				}

				.badge {
					display: flex;
					align-items: center;
					height: 20px;

					img {
						width: auto;
						height: 24px;
					}

					span {
						font-family: fonts.$DM-Sans;
						font-weight: 400;
						font-size: fonts.rem(14px);
						line-height: 1.4;
						letter-spacing: -0.28px;
						color: colors.$color-gray;
						text-align: center;
					}
				}
			}
		}
	}
}
